mapper.select:
SELECT COUNT(*) AS CNT FROM RCA.TB_ANOMALOUS_TRAFFIC
WHERE STRIFID = #{strifid}
 AND INTTIMESTAMP = #{inttimestamp} ::integer

SELECT COUNT(*) AS CNT
  FROM RCA.TB_NOXIOUS_TRAFFIC
 WHERE DATEREGDATE = #{dateregdate} ::timestamp
   AND STRRESIP = #{strresip}
   AND STRS_IP = #{strsIp}
   AND STRS_PORT = #{strsPort}
   AND STRD_IP = #{strdIp}
   AND STRD_PORT = #{strdPort}

SELECT COUNT(*) AS CNT
 FROM RCA.TB_ANOMALOUS_1MI_TRAFFIC
WHERE MEASURED_DATETIME = to_timestamp(cast(#{measured_datetime} AS int8)/1000)
 AND STRRESID = #{strresid}
 AND STRIFID = #{strifid}

mapper.insert:
INSERT INTO RCA.TB_NOXIOUS_TRAFFIC
SELECT DISTINCT NULL, NM.NODE_NUM, SL.STRRESIP, SL.STRRESNAME, SL.STRS_IP
     , SL.STRS_PORT, SL.STRD_IP, SL.STRD_PORT, SL.STRS_MAC, SL.STRD_MAC
     , SL.STRPROTOCOL, SL.STRIPV4TOS, SL.STRCHANNEL, SL.STRSENDERIP, SL.STRIN_INTERFACE
     , SL.STROUT_INTERFACE, SL.STRBYTES_COL, SL.STRCOUNTS, SL.DATEREGDATE
  FROM IP_YD.XE_SFLOW_LOG SL
  LEFT OUTER JOIN RESOURCE.TB_NODE_MST NM
    ON SL.STRRESIP = NM.IP_ADDR
 WHERE SL.DATEREGDATE = #{dateregdate} ::timestamp
   AND SL.STRRESIP = #{strresip}
   AND SL.STRS_IP = #{strsIp}
   AND SL.STRS_PORT = #{strsPort}
   AND SL.STRD_IP = #{strdIp}
   AND SL.STRD_PORT = #{strdPort}

INSERT INTO RCA.TB_ANOMALOUS_1MI_TRAFFIC SELECT NULL, #{trafficGb} ,PM.IF_NUM AS STRIFID , I.IF_NAME AS STRIFNM, NM.NODE_NUM AS STRRESID, NM.NODE_NM AS STRRESNM, LT.MEASURED_DATETIME, LT.RX_BIT_RATE AS FLTBPSIN ,LT.TX_BIT_RATE AS FLTBPSOUT , LT.RX_PKT_RATE AS FLTPPSIN , LT.TX_PKT_RATE AS FLTPPSOUT , NOW() FROM IP_SDN.TB_LINK_TRAFFIC LT INNER JOIN( SELECT ID, LOWER(IF_NAME) AS IF_NAME, NODE_ID FROM IP_SDN.TB_INTERFACE ) I ON LT.IF_ID = I.ID INNER JOIN RESOURCE.TB_PORT_MST PM ON PM.IF_ID = I.IF_NAME INNER JOIN IP_SDN.TB_NODE N ON I.NODE_ID = N.ID INNER JOIN ( SELECT IP_SDN_ID::INT, NODE_ID, NODE_NUM, NODE_NM FROM RESOURCE.TB_NODE_MST ) NM ON N.ID = NM.IP_SDN_ID WHERE PM.NODE_NUM = NM.NODE_NUM
AND PM.IF_NUM = #{strifid}
AND NM.NODE_NUM = #{strresid}
AND LT.MEASURED_DATETIME = to_timestamp(cast(#{measured_datetime} AS int8)/1000)

INSERT INTO RCA.TB_NODEFACTOR_AI_RESULT
(
  strresid, measured_datetime, predicted_time, cpu_predicted, mem_predicted
)
VALUES
(
  (SELECT NM.NODE_NUM  FROM RESOURCE.TB_NODE_MST NM
  WHERE IP_SDN_ID = #{id}),to_timestamp(#{measured_datetime}/1000),#{predicted_time},#{cpu_usage},#{mem_usage}
)
